import Header from "../../components/Header/Header";
import classes from "./Chat.module.css";
import ChatForm from "../../components/Chat/ChatForm";
import React, { useState, useEffect } from "react";
import ChatMessage from "../../components/Chat/ChatMessage";

const Chat = (props) => {
  const MESSAGES = [
    { message_id: 1, user_id: 1, user: "Bob", message: "Yo", time: "" },
    { message_id: 2, user_id: 2, user: "Eric", message: "Hello", time: "0" },
    { message_id: 3, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 4, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 5, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 6, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 7, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 8, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 9, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 10, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 11, user_id: 2, user: "Eric", message: "Hello", time: "" },
    { message_id: 12, user_id: 2, user: "Eric", message: "Hello", time: "" },
    anchor
  ];

  const [messages, setMessages] = useState(MESSAGES);

  return (
    <div className={classes["container"]}>
      <Header
        title="Bob"
        avatar="https://animedao.to/images/call-of-the-night.jpg"
        tabBar={false}
      ></Header>
      <div className={classes["messages-wrapper"]}>
        <ol className={classes["messages"]}>
          {MESSAGES.map((item) => (
            <ChatMessage
              key={item.message_id}
              message={item.message}
              user={item.user}
              avatar="https://animedao.to/images/call-of-the-night.jpg"
            ></ChatMessage>
          ))}
          <div className={classes["messages-spacer"]}></div>
        </ol>
      </div>
      <ChatForm></ChatForm>
    </div>
  );
};

export default Chat;
